import torch
import torch.nn as nn
import torch.optim as optim
from torchvision import datasets, transforms, models
import requests
from io import BytesIO

def download_model(url):
    response = requests.get(url)
    response.raise_for_status()
    return torch.load(BytesIO(response.content), map_location=torch.device('cpu'))

def fine_tune_model(model, train_loader, num_classes, num_epochs=5):
    for param in model.parameters():
        param.requires_grad = False

    model.fc = nn.Linear(model.fc.in_features, num_classes)
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.SGD(model.fc.parameters(), lr=0.001, momentum=0.9)

    model.train()
    for epoch in range(num_epochs):
        running_loss = 0.0
        for inputs, labels in train_loader:
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
            running_loss += loss.item()
        print(f'Epoch {epoch+1}, Loss: {running_loss/len(train_loader)}')

def main():
    model_url = 'https://example.com/path/to/pretrained/model.pth'
    model = download_model(model_url)
    
    transform = transforms.Compose([transforms.Resize(256), transforms.CenterCrop(224), transforms.ToTensor()])
    train_dataset = datasets.FakeData(transform=transform)
    train_loader = torch.utils.data.DataLoader(train_dataset, batch_size=4, shuffle=True)

    num_classes = 10
    fine_tune_model(model, train_loader, num_classes)

if __name__ == '__main__':
    main()